#include <stdio.h>
#include <stdlib.h>

struct Node {
    char data;
    struct Node* left;
    struct Node* right;
};

struct Queue {
    struct Node** items;
    int front, rear, size;
};

void levelOrder(struct Node* root) {
    if (root == NULL) return;

    struct Queue q;
    q.size = 100;
    q.front = q.rear = 0;
    q.items = malloc(q.size * sizeof(struct Node*));

    enqueue(&q, root);

    while (!isEmpty(&q)) {
        struct Node* temp = dequeue(&q);
        printf("%c ", temp->data);

        if (temp->left) enqueue(&q, temp->left);
        if (temp->right) enqueue(&q, temp->right);
    }
}

// Recursive Postorder
class TreeTraversal {
    void postorderRecursive(Node root) {
        if (root == null) return;
        postorderRecursive(root.left);   // Traverse left
        postorderRecursive(root.right);  // Traverse right
        visit(root);                      // Visit node
    }

    // Iterative Postorder using Two Stacks
    void postorderIterative(Node root) {
        if (root == null) return;
        Stack<Node> s1 = new Stack<>();
        Stack<Node> s2 = new Stack<>();
        s1.push(root);

        while (!s1.isEmpty()) {
            Node temp = s1.pop();
            s2.push(temp);
            if (temp.left != null) s1.push(temp.left);
            if (temp.right != null) s1.push(temp.right);
        }

        while (!s2.isEmpty()) {
            visit(s2.pop());
        }
    }
}
